import logging
from dataclasses import dataclass
from typing import Dict
import unittest

# Configure logging for production-grade event tracking
logging.basicConfig(level=logging.INFO, format='%(levelname)s: %(message)s')
logger = logging.getLogger(__name__)

@dataclass
class InventoryItem:
    """Data model representing an inventory item."""
    item_id: str
    name: str
    quantity: int

class InventoryManager:
    """Service layer for managing inventory operations."""

    LOW_STOCK_THRESHOLD = 5

    def __init__(self) -> None:
        self._items: Dict[str, InventoryItem] = {}

    def _validate_quantity(self, quantity: int) -> None:
        """Ensures quantity is a non-negative integer."""
        if not isinstance(quantity, int) or quantity < 0:
            raise ValueError("Quantity must be a non-negative integer.")

    def add_item(self, item: InventoryItem) -> None:
        """Adds a new item to the inventory."""
        if item.item_id in self._items:
            raise ValueError(f"Item ID '{item.item_id}' already exists.")
        self._validate_quantity(item.quantity)
        self._items[item.item_id] = item
        logger.info(f"Added item: {item.name} (ID: {item.item_id})")

    def update_stock(self, item_id: str, amount: int) -> None:
        """Updates stock levels and triggers alerts if below threshold."""
        if item_id not in self._items:
            raise KeyError(f"Item ID '{item_id}' not found.")

        item = self._items[item_id]
        new_quantity = item.quantity + amount

        if new_quantity < 0:
            raise ValueError("Resulting stock level cannot be negative.")

        item.quantity = new_quantity

        if item.quantity < self.LOW_STOCK_THRESHOLD:
            logger.warning(f"LOW STOCK ALERT: {item.name} (ID: {item_id}) is at {item.quantity} units.")

class TestInventoryManager(unittest.TestCase):
    """Unit test suite for InventoryManager."""

    def setUp(self) -> None:
        self.manager = InventoryManager()
        self.item = InventoryItem("A1", "Widget", 10)

    def test_add_item(self) -> None:
        self.manager.add_item(self.item)
        self.assertIn("A1", self.manager._items)

    def test_update_stock_success(self) -> None:
        self.manager.add_item(self.item)
        self.manager.update_stock("A1", -6)
        self.assertEqual(self.manager._items["A1"].quantity, 4)

    def test_negative_stock_prevention(self) -> None:
        self.manager.add_item(self.item)
        with self.assertRaises(ValueError):
            self.manager.update_stock("A1", -15)

    def test_low_stock_alert(self) -> None:
        self.manager.add_item(self.item)
        with self.assertLogs(logger, level='WARNING') as cm:
            self.manager.update_stock("A1", -7)
            self.assertTrue(any("LOW STOCK ALERT" in output for output in cm.output))

if __name__ == "__main__":
    unittest.main()
